import api from "./api";
import { getAuthHeaders } from "./authService";
// Hàm xử lý thanh toán
export const processPayment = ({ orderId, paymentIntentId, walletAddress }) => {
  return api.post("/payments/process", {
    orderId,
    paymentIntentId,
    walletAddress,
  }, {
    headers: getUserFromLocalStorage()
  });
};
// Lấy danh sách sự kiện
export const getAllEvents = async (isAdmin = false, params = {}) => {
  const endpoint = isAdmin ? "/admin/events" : "/users/events";
  try {
    const response = await api.get(endpoint, {
      params,
      headers: getAuthHeaders(),
    });
    return response;
  } catch (error) {
    console.error("Lỗi khi lấy sự kiện:", error);
    throw new Error("Không thể lấy danh sách sự kiện");
  }
};

// Lấy chi tiết sự kiện theo ID
// Lấy chi tiết sự kiện theo ID
export const getEventById = async (id, isAdmin = false) => {
  const endpoint = isAdmin ? `/admin/events/${id}` : `/users/events/${id}`;
  try {
    const response = await api.get(endpoint, {
      headers: getAuthHeaders(),
    });
    if (!response.data?.data) {
      throw new Error("Không tìm thấy sự kiện này.");
    }
    return response;
  } catch (error) {
    console.error("Lỗi khi lấy chi tiết sự kiện:", error);
    if (error.response) {
      // Handle API error response
      throw new Error(`Lỗi API: ${error.response.data.message || error.message}`);
    } else {
      // Handle other errors
      throw new Error(error.message || "Đã xảy ra lỗi khi lấy chi tiết sự kiện.");
    }
  }
};

// Lấy ticket types public theo event
export const getPublicTicketTypesByEvent = async (eventId) => {
  try {
    const response = await api.get(`/users/events/${eventId}/ticket-types`, {
      headers: getAuthHeaders(),
    });
    return response;
  } catch (error) {
    console.error("Lỗi khi lấy ticket types:", error);
    throw new Error("Không thể lấy ticket types cho sự kiện");
  }
};

// Ghép chi tiết event + ticket types cho phía user
export const getEventDetailWithTickets = async (id, isAdmin = false) => {
  if (isAdmin) {
    const eventRes = await api.get(`/admin/events/${id}`, {
      headers: getAuthHeaders(),
    });
    return {
      data: {
        success: eventRes.data?.success ?? true,
        message: eventRes.data?.message || "Lấy chi tiết sự kiện thành công",
        data: eventRes.data?.data || null,
      },
    };
  }

  const [eventRes, ticketTypeRes] = await Promise.all([
    api.get(`/users/events/${id}`, {
      headers: getAuthHeaders(),
    }),
    api.get(`/users/events/${id}/ticket-types`, {
      headers: getAuthHeaders(),
    }),
  ]);

  return {
    data: {
      success: true,
      message: "Lấy chi tiết sự kiện thành công",
      data: {
        ...(eventRes.data?.data || {}),
        ticket_types: ticketTypeRes.data?.data?.ticket_types || [],
      },
    },
  };
};

// Admin create
export const adminCreateEvent = (data) => {
  return api.post("/admin/events", data, {
    headers: getAuthHeaders(),
  });
};

// Admin update
export const adminUpdateEvent = (id, data) => {
  return api.put(`/admin/events/${id}`, data, {
    headers: getAuthHeaders(),
  });
};

// Admin delete
export const adminDeleteEvent = (id) => {
  return api.delete(`/admin/events/${id}`, {
    headers: getAuthHeaders(),
  });
};
